public class TestRunner {
    static int passed = 0;
    static int failed = 0;

    public static void main(String[] args) {

        // ══════════════ Monster ══════════════
        try {
            Monster g = new Monster("Goblin", 30);
            check("Monster.getName()", "Goblin", g.getName());
        } catch (Exception e) { fail("Monster.getName()", e); }

        try {
            Monster g = new Monster("Goblin", 30);
            check("Monster.getHealth()", "30", String.valueOf(g.getHealth()));
        } catch (Exception e) { fail("Monster.getHealth()", e); }

        try {
            Monster g = new Monster("Goblin", -5);
            check("Monster constructor clamps negative health",
                  "0", String.valueOf(g.getHealth()));
        } catch (Exception e) { fail("Monster health clamp", e); }

        // ── takeDamage ──
        try {
            Monster g = new Monster("Goblin", 30);
            g.takeDamage(10);
            check("takeDamage(10) from 30",
                  "20", String.valueOf(g.getHealth()));
        } catch (Exception e) { fail("takeDamage(10)", e); }

        try {
            Monster g = new Monster("Goblin", 30);
            g.takeDamage(50);
            check("takeDamage(50) from 30 clamps to 0",
                  "0", String.valueOf(g.getHealth()));
        } catch (Exception e) { fail("takeDamage clamp", e); }

        try {
            Monster g = new Monster("Goblin", 30);
            g.takeDamage(-5);
            check("takeDamage(-5) ignored",
                  "30", String.valueOf(g.getHealth()));
        } catch (Exception e) { fail("takeDamage negative", e); }

        // ── isDefeated ──
        try {
            Monster g = new Monster("Goblin", 30);
            check("isDefeated() — alive",
                  "false", String.valueOf(g.isDefeated()));
        } catch (Exception e) { fail("isDefeated false", e); }

        try {
            Monster g = new Monster("Goblin", 30);
            g.takeDamage(30);
            check("isDefeated() — dead",
                  "true", String.valueOf(g.isDefeated()));
        } catch (Exception e) { fail("isDefeated true", e); }

        // ── Monster toString ──
        try {
            Monster g = new Monster("Goblin", 30);
            check("Monster.toString()",
                  "Goblin [HP=30]", g.toString());
        } catch (Exception e) { fail("Monster.toString()", e); }

        try {
            Monster d = new Monster("Dragon", 200);
            d.takeDamage(50);
            check("Monster.toString() after damage",
                  "Dragon [HP=150]", d.toString());
        } catch (Exception e) { fail("Monster.toString() after damage", e); }

        // ══════════════ Dungeon ══════════════
        try {
            Dungeon dun = new Dungeon("Dark Cave");
            check("Dungeon.getMonsterCount() — empty",
                  "0", String.valueOf(dun.getMonsterCount()));
        } catch (Exception e) { fail("Dungeon empty count", e); }

        try {
            Dungeon dun = new Dungeon("Dark Cave");
            check("Dungeon.toString() — empty",
                  "Dark Cave (0 monsters)", dun.toString());
        } catch (Exception e) { fail("Dungeon.toString() empty", e); }

        // ── addMonster + count ──
        try {
            Dungeon dun = new Dungeon("Dark Cave");
            dun.addMonster(new Monster("Goblin", 30));
            dun.addMonster(new Monster("Orc", 60));
            check("addMonster + getMonsterCount()",
                  "2", String.valueOf(dun.getMonsterCount()));
        } catch (Exception e) { fail("addMonster + count", e); }

        // ── listMonsters — empty ──
        try {
            Dungeon dun = new Dungeon("Dark Cave");
            check("listMonsters() — empty",
                  "The dungeon is empty.", dun.listMonsters());
        } catch (Exception e) { fail("listMonsters() empty", e); }

        // ── listMonsters — populated ──
        try {
            Dungeon dun = new Dungeon("Dark Cave");
            dun.addMonster(new Monster("Goblin", 30));
            dun.addMonster(new Monster("Dragon", 200));
            check("listMonsters() — 2 monsters",
                  "Goblin [HP=30]\nDragon [HP=200]",
                  dun.listMonsters());
        } catch (Exception e) { fail("listMonsters() populated", e); }

        // ── Dungeon toString ──
        try {
            Dungeon dun = new Dungeon("Dark Cave");
            dun.addMonster(new Monster("Goblin", 30));
            dun.addMonster(new Monster("Orc", 60));
            dun.addMonster(new Monster("Dragon", 200));
            check("Dungeon.toString()",
                  "Dark Cave (3 monsters)", dun.toString());
        } catch (Exception e) { fail("Dungeon.toString()", e); }

        // ── attackAll — no defeats ──
        try {
            Dungeon dun = new Dungeon("Cave");
            dun.addMonster(new Monster("Goblin", 30));
            dun.addMonster(new Monster("Orc", 60));
            int defeated = dun.attackAll(10);
            check("attackAll(10) — no defeats",
                  "0", String.valueOf(defeated));
        } catch (Exception e) { fail("attackAll no defeats", e); }

        try {
            Dungeon dun = new Dungeon("Cave");
            dun.addMonster(new Monster("Goblin", 30));
            dun.addMonster(new Monster("Orc", 60));
            dun.attackAll(10);
            check("attackAll(10) — count unchanged",
                  "2", String.valueOf(dun.getMonsterCount()));
        } catch (Exception e) { fail("attackAll count unchanged", e); }

        // ── attackAll — some defeated ──
        try {
            Dungeon dun = new Dungeon("Cave");
            dun.addMonster(new Monster("Goblin", 20));
            dun.addMonster(new Monster("Orc", 60));
            dun.addMonster(new Monster("Slime", 10));
            int defeated = dun.attackAll(25);
            check("attackAll(25) — 2 defeated",
                  "2", String.valueOf(defeated));
        } catch (Exception e) { fail("attackAll some defeated", e); }

        try {
            Dungeon dun = new Dungeon("Cave");
            dun.addMonster(new Monster("Goblin", 20));
            dun.addMonster(new Monster("Orc", 60));
            dun.addMonster(new Monster("Slime", 10));
            dun.attackAll(25);
            check("attackAll(25) — 1 remains",
                  "1", String.valueOf(dun.getMonsterCount()));
        } catch (Exception e) { fail("attackAll remains", e); }

        // ── attackAll — all defeated ──
        try {
            Dungeon dun = new Dungeon("Cave");
            dun.addMonster(new Monster("Goblin", 20));
            dun.addMonster(new Monster("Slime", 5));
            int defeated = dun.attackAll(100);
            check("attackAll(100) — all defeated",
                  "2", String.valueOf(defeated));
        } catch (Exception e) { fail("attackAll all defeated", e); }

        try {
            Dungeon dun = new Dungeon("Cave");
            dun.addMonster(new Monster("Goblin", 20));
            dun.addMonster(new Monster("Slime", 5));
            dun.attackAll(100);
            check("attackAll(100) — dungeon now empty",
                  "The dungeon is empty.", dun.listMonsters());
        } catch (Exception e) { fail("attackAll empty after", e); }

        // ══════════════ Encapsulation ══════════════
        try {
            java.lang.reflect.Field f = Monster.class.getDeclaredField("health");
            check("Monster.health is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("Monster.health field exists", new Exception("Field 'health' not found"));
        } catch (Exception e) { fail("Monster.health is private", e); }

        try {
            java.lang.reflect.Field f = Dungeon.class.getDeclaredField("monsters");
            check("Dungeon.monsters is private", "true",
                  String.valueOf(java.lang.reflect.Modifier.isPrivate(f.getModifiers())));
        } catch (NoSuchFieldException e) {
            fail("Dungeon.monsters field exists", new Exception("Field 'monsters' not found"));
        } catch (Exception e) { fail("Dungeon.monsters is private", e); }
    }

    static void check(String label, String expected, String actual) {
        if (expected.equals(actual)) {
            System.out.println("PASS: " + label); passed++;
        } else {
            System.out.println("FAIL: " + label
                + " \u2014 expected \"" + expected
                + "\" but got \"" + actual + "\""); failed++;
        }
    }
    static void fail(String label, Exception e) {
        System.out.println("FAIL: " + label + " \u2014 " + e.getMessage()); failed++;
    }
}
